//! Golden file tests for JSON output stability.
//!
//! These tests ensure that JSON output (used by AI agents) NEVER changes unexpectedly.
//! Any change to JSON structure could break agent integrations.

use std::path::Path;
use std::process::Command;
use serde_json::Value;
use tracing::{info, warn, error};

/// Initialize test logging with detailed output
fn init_test_logging() {
    let _ = tracing_subscriber::fmt()
        .with_env_filter("debug")
        .with_test_writer()
        .try_init();
}

/// Run dcg in robot mode and capture output
fn run_robot_mode(command: &str) -> DcgOutput {
    init_test_logging();
    info!("Running robot mode: {}", command);

    let binary = find_dcg_binary();
    let start = std::time::Instant::now();

    let output = Command::new(&binary)
        .args(["--robot", "test", command])
        .output()
        .expect("failed to run dcg");

    let elapsed = start.elapsed();
    info!("Command completed in {:?}", elapsed);

    DcgOutput {
        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
        exit_code: output.status.code().unwrap_or(-1),
    }
}

/// Compare JSON output against golden file with detailed diff
fn assert_json_matches_golden(actual: &str, golden_path: &str) {
    init_test_logging();

    let golden_full_path = Path::new("tests/golden").join(golden_path);
    info!("Comparing against golden file: {:?}", golden_full_path);

    let golden_content = match std::fs::read_to_string(&golden_full_path) {
        Ok(c) => c,
        Err(e) => {
            // If UPDATE_GOLDEN=1, create the golden file
            if std::env::var("UPDATE_GOLDEN").is_ok() {
                warn!("Creating new golden file: {:?}", golden_full_path);
                if let Some(parent) = golden_full_path.parent() {
                    std::fs::create_dir_all(parent).ok();
                }
                std::fs::write(&golden_full_path, actual).expect("failed to write golden");
                return;
            }
            panic!("Golden file not found: {:?}: {}", golden_full_path, e);
        }
    };

    let actual_json: Value = serde_json::from_str(actual)
        .expect("Actual output is not valid JSON");
    let golden_json: Value = serde_json::from_str(&golden_content)
        .expect("Golden file is not valid JSON");

    if actual_json != golden_json {
        let diff = json_diff(&golden_json, &actual_json);
        error!("JSON mismatch detected!");
        error!("Differences:\n{}", diff);

        // If UPDATE_GOLDEN=1, update the file
        if std::env::var("UPDATE_GOLDEN").is_ok() {
            warn!("Updating golden file due to UPDATE_GOLDEN=1");
            std::fs::write(&golden_full_path, actual).expect("failed to update golden");
            return;
        }

        panic!(
            "JSON output differs from golden file '{}':\n\n{}\n\nActual:\n{}\n\nExpected:\n{}",
            golden_path, diff, actual, golden_content
        );
    }

    info!("Golden file match: OK");
}

/// Generate detailed JSON diff
fn json_diff(expected: &Value, actual: &Value) -> String {
    let mut diffs = Vec::new();

    fn diff_values(path: &str, exp: &Value, act: &Value, diffs: &mut Vec<String>) {
        match (exp, act) {
            (Value::Object(e), Value::Object(a)) => {
                for key in e.keys() {
                    if !a.contains_key(key) {
                        diffs.push(format!("  MISSING: {}.{}", path, key));
                    }
                }
                for key in a.keys() {
                    if !e.contains_key(key) {
                        diffs.push(format!("  EXTRA: {}.{} = {:?}", path, key, a[key]));
                    }
                }
                for key in e.keys().filter(|k| a.contains_key(*k)) {
                    diff_values(&format!("{}.{}", path, key), &e[key], &a[key], diffs);
                }
            }
            (Value::Array(e), Value::Array(a)) => {
                if e.len() != a.len() {
                    diffs.push(format!("  LENGTH: {} expected {} items, got {}", path, e.len(), a.len()));
                }
                for (i, (ev, av)) in e.iter().zip(a.iter()).enumerate() {
                    diff_values(&format!("{}[{}]", path, i), ev, av, diffs);
                }
            }
            _ if exp != act => {
                diffs.push(format!("  CHANGED: {} expected {:?} got {:?}", path, exp, act));
            }
            _ => {}
        }
    }

    diff_values("$", expected, actual, &mut diffs);

    if diffs.is_empty() {
        "No differences".to_string()
    } else {
        diffs.join("\n")
    }
}
